public class StringConstructors {
 public static void main(String[] args) {
 // Default constructor
 String emptyString = new String();
 System.out.println(emptyString);

 // From character array
 char[] charArray = {'H', 'e', 'l', 'l', 'o'};
 String fromCharArray = new String(charArray);
 System.out.println(fromCharArray);

 // From byte array
 byte[] byteArray = {72, 101, 108, 108, 111};
 String fromByteArray = new String(byteArray);
 System.out.println(fromByteArray);

 // From another string
 String original = "Hello";
 String copy = new String(original);
 System.out.println(copy);
 }
}

public class StringConstructorsAdvanced {
 public static void main(String[] args) {
 // From portion of character array
 char[] chars = {'J', 'a', 'v', 'a', 'P', 'r', 'o', 'g', 'r', 'a', 'm'};
 String substringFromArray = new String(chars, 4, 7);
 System.out.println(substringFromArray);

 // From byte array with specific charset
 try {
 byte[] bytes = "Hello".getBytes("UTF-8");
 String fromBytesWithCharset = new String(bytes, "UTF-8");
 System.out.println(fromBytesWithCharset);
 } catch (UnsupportedEncodingException e) {
 e.printStackTrace();
 }
 }
}
